MERGE INTO CONSULTAS FIN USING (SELECT '800565ReporteBusquedaDocSoporte' INFORME ,TO_CLOB(q'[SELECT ESTADOFAC.NUMERO, ESTADOFAC.PREFIJO, ESTADOFAC.ESTADO, 
ESTADOFAC.TOTAL AS VALOR_TOTAL, TO_CHAR(ESTADOFAC.FECHA, 'DD-MM-YYYY') AS FECHA,  
ESTADOFAC.OBSERVACION AS CUFE, COMPROBANTE_CNT.TERCERO 
FROM ESTADOFAC
INNER JOIN COMPROBANTE_CNT ON COMPANIA = s$compania$s
AND ESTADOFAC.NUMERO = COMPROBANTE_CNT.CONSECUTIVODIAN 
AND ESTADOFAC.PREFIJO = COMPROBANTE_CNT.PREFIJODIAN 
ORDER BY
    ESTADOFAC.NUMERO DESC]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'MROSERO' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);